import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider } from "./contexts/AuthContext";
import ProtectedRoute from "./components/ProtectedRoute";
import LoginPage     from "./pages/LoginPage";
import SignupPage    from "./pages/SignupPage";
import "./index.css";

// Temporary placeholder pages
const DashboardPage  = () => <div style={{padding:32,fontFamily:"sans-serif"}}><h1>Dashboard</h1></div>;
const ProductsPage   = () => <div style={{padding:32,fontFamily:"sans-serif"}}><h1>Products</h1></div>;
const AnalyticsPage  = () => <div style={{padding:32,fontFamily:"sans-serif"}}><h1>Analytics</h1></div>;

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/login"     element={<LoginPage/>}/>
          <Route path="/signup"    element={<SignupPage/>}/>
          <Route path="/dashboard" element={<ProtectedRoute><DashboardPage/></ProtectedRoute>}/>
          <Route path="/products"  element={<ProtectedRoute><ProductsPage/></ProtectedRoute>}/>
          <Route path="/analytics" element={<ProtectedRoute><AnalyticsPage/></ProtectedRoute>}/>
          <Route path="*"          element={<Navigate to="/login" replace/>}/>
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}
